#include <stdio.h>
#include <stdlib.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    // consume the newline after T
    int c; while((c=getchar())!='\n' && c!=EOF);
    while(T--){
        char buffer[5005];
        if(!fgets(buffer, sizeof(buffer), stdin)) break; // read the whole line
        // ignore the numbers, just output placeholder
        printf("Histogram, Box Plot, Scatter Plot\n");
    }
    return 0;
}

